#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define N 100005
#define K 81

typedef long long ll;

ll a[N], p[N], s[N], t[N];

int main() {
    int n, q, k, i, j, l, r, c, d, e, f, g, h, m;
    ll x, y, z, u, v, w;

    scanf("%d%d%d", &n, &q, &k);
    for (i = 1; i <= n; i++) {
        scanf("%lld", &a[i]);
        p[i] = a[i];
        s[i] = s[i - 1] + a[i];
    }

    for (i = 1; i <= n; i++) {
        for (j = 2; j <= sqrt(a[i]); j++) {
            while (a[i] % j == 0) {
                a[i] /= j;
                p[i] *= j;
            }
        }
        if (a[i] > 1) {
            p[i] *= a[i];
        }
    }

    for (i = 1; i <= n; i++) {
        t[i] = t[i - 1] + p[i];
    }

    for (i = 1; i <= n; i++) {
        for (j = i; j <= n; j += i) {
            if (t[j] % k == 0) {
                w = t[j] / k;
                for (c = 1; c <= n; c++) {
                    if (t[c] <= w) {
                        w -= t[c];
                    }
                }
                if (w == 0) {
                    printf("%lld\n", s[j] - s[i - 1]);
                    break;
                }
            }
        }
    }

    for (i = 1; i <= q; i++) {
        scanf("%d%d", &l, &r);
        w = 0;
        for (c = l; c <= r; c++) {
            w += p[c];
        }
        if (w % k == 0) {
            printf("%lld\n", s[r] - s[l - 1]);
        } else {
            printf("-1\n");
        }
    }

    return 0;
}

