const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let n, q, k;
let a = [], p = [], s = [], t = [];

readline.on('line', line => {
    if (!n) {
        [n, q, k] = line.split(' ').map(Number);
    } else if (a.length < n) {
        a.push(Number(line));
        p.push(a[a.length - 1]);
        s.push(s[s.length - 1] + a[a.length - 1]);
    } else if (a.length === n) {
        for (let i = 1; i <= n; i++) {
            for (let j = 2; j <= Math.sqrt(a[i - 1]); j++) {
                while (a[i - 1] % j === 0) {
                    a[i - 1] /= j;
                    p[i - 1] *= j;
                }
            }
            if (a[i - 1] > 1) {
                p[i - 1] *= a[i - 1];
            }
        }

        for (let i = 1; i <= n; i++) {
            t[i] = t[i - 1] + p[i - 1];
        }

        for (let i = 1; i <= n; i++) {
            for (let j = i; j <= n; j += i) {
                if (t[j] % k === 0) {
                    let w = t[j] / k;
                    for (let c = 1; c <= n; c++) {
                        if (t[c] <= w) {
                            w -= t[c];
                        }
                    }
                    if (w === 0) {
                        console.log(s[j] - s[i - 1]);
                        break;
                    }
                }
            }
        }

        for (let i = 1; i <= q; i++) {
            let [l, r] = line.split(' ').map(Number);
            let w = 0;
            for (let c = l; c <= r; c++) {
                w += p[c - 1];
            }
            if (w % k === 0) {
                console.log(s[r] - s[l - 1]);
            } else {
                console.log(-1);
            }
        }
    }
});

